// ===== CAPTIONS =====
const CAPTIONS = [
  'Always herself ✨',
  'Too cute for words 💕',
  'Pure vibes 🌟',
  'Serving looks 💖',
  'That smile though 🌹',
  'Iconic 👑',
  'Living her best life ✨',
  'Sunshine energy ☀️',
  'Effortlessly her 💫',
  'Goals 🔥',
  'Blessed ❤️',
  'Glowing as always ✨',
  'Peace ✌️',
  'Real one 💯',
  'Unforgettable 🌹'
];

// ===== STATE =====
let currentSlide = 0;
let galleryTimer = null;

// ===== PAGE TRANSITION =====
function goToPage(fromId, toId, delay = 0) {
  setTimeout(() => {
    const from = document.getElementById(fromId);
    const to   = document.getElementById(toId);
    if (from) { from.classList.remove('active'); from.classList.add('exit'); setTimeout(()=>from.classList.remove('exit'),1000); }
    if (to)   { to.classList.add('active'); }
  }, delay);
}

// ===== TYPEWRITER =====
function typeWriter(elementId, text, speed, callback) {
  const el = document.getElementById(elementId);
  if (!el) return;
  let i = 0;
  el.textContent = '';
  function tick() {
    if (i < text.length) { el.textContent += text[i++]; setTimeout(tick, speed); }
    else if (callback) setTimeout(callback, 400);
  }
  tick();
}

// ===== FLOATING HEARTS =====
function spawnHearts(containerId, count, interval) {
  const container = document.getElementById(containerId);
  if (!container) return;
  const hearts = ['❤️','💕','💖','💗','💓','🌹','✨','💫'];
  let spawned = 0;
  const id = setInterval(() => {
    if (count && spawned >= count) { clearInterval(id); return; }
    const h = document.createElement('div');
    h.className = 'fheart';
    h.textContent = hearts[Math.floor(Math.random()*hearts.length)];
    h.style.left = Math.random()*100 + '%';
    h.style.bottom = '-5%';
    h.style.fontSize = (0.8 + Math.random()*1.2) + 'rem';
    h.style.animationDuration = (5 + Math.random()*6) + 's';
    h.style.animationDelay = (Math.random()*2) + 's';
    container.appendChild(h);
    setTimeout(() => h.remove(), 12000);
    spawned++;
  }, interval || 600);
  return id;
}

// ===== PARTICLES =====
function spawnParticles(containerId, count) {
  const container = document.getElementById(containerId);
  if (!container) return;
  const colors = ['#ff6b9d','#ffd700','#c084fc','#ffb3c6','#ff3d7f','#fff'];
  for (let i=0; i<count; i++) {
    const p = document.createElement('div');
    p.className = 'particle';
    const size = 2 + Math.random()*4;
    p.style.cssText = `
      width:${size}px; height:${size}px;
      left:${Math.random()*100}%;
      top:${Math.random()*100}%;
      background:${colors[Math.floor(Math.random()*colors.length)]};
      animation-duration:${3+Math.random()*5}s;
      animation-delay:${Math.random()*4}s;
      opacity:${0.3+Math.random()*0.5};
    `;
    container.appendChild(p);
  }
}

// ===== CONFETTI =====
function launchConfetti() {
  const canvas = document.getElementById('confetti-canvas');
  if (!canvas) return;
  const ctx = canvas.getContext('2d');
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
  const pieces = [];
  const colors = ['#ff6b9d','#ffd700','#c084fc','#ff3d7f','#ffb3c6','#fff','#9b59b6'];
  for (let i=0; i<120; i++) {
    pieces.push({
      x: Math.random()*canvas.width,
      y: Math.random()*canvas.height - canvas.height,
      w: 6+Math.random()*8, h: 4+Math.random()*6,
      color: colors[Math.floor(Math.random()*colors.length)],
      rot: Math.random()*360,
      speed: 1.5+Math.random()*2.5,
      drift: (Math.random()-0.5)*1.5,
      rotSpeed: (Math.random()-0.5)*4
    });
  }
  let frame;
  function draw() {
    ctx.clearRect(0,0,canvas.width,canvas.height);
    pieces.forEach(p => {
      ctx.save();
      ctx.translate(p.x, p.y);
      ctx.rotate(p.rot*Math.PI/180);
      ctx.fillStyle = p.color;
      ctx.globalAlpha = 0.85;
      ctx.fillRect(-p.w/2,-p.h/2,p.w,p.h);
      ctx.restore();
      p.y += p.speed; p.x += p.drift; p.rot += p.rotSpeed;
      if (p.y > canvas.height) { p.y = -10; p.x = Math.random()*canvas.width; }
    });
    frame = requestAnimationFrame(draw);
  }
  draw();
  setTimeout(() => { cancelAnimationFrame(frame); ctx.clearRect(0,0,canvas.width,canvas.height); }, 5500);
}

// ===== PAGE 1: WELCOME =====
function initWelcome() {
  spawnHearts('floating-hearts-welcome', 0, 800);
  spawnParticles('welcome-particles', 40);
  launchConfetti();
  typeWriter('welcome-title', 'Happy Birthday Ajewole Damisola Moyosola 🎉❤️', 60, () => {
    typeWriter('welcome-sub', 'A beautiful surprise has been prepared specially for you ✨', 50, null);
  });
  setTimeout(() => {
    goToPage('page-welcome', 'page-lock');
    setTimeout(initLock, 500);
  }, 6000);
}

// ===== PAGE 2: LOCK =====
function initLock() {
  document.getElementById('lock-bg').style.backgroundImage = `url('${IMGS[0]}')`;
  spawnHearts('floating-hearts-lock', 0, 1200);
  spawnParticles('lock-particles', 25);
  updateClock();
  setInterval(updateClock, 1000);
  document.getElementById('lock-input').addEventListener('keydown', e => {
    if (e.key === 'Enter') checkPassword();
  });
}

function updateClock() {
  const now = new Date();
  let h = now.getHours().toString().padStart(2,'0');
  let m = now.getMinutes().toString().padStart(2,'0');
  document.getElementById('lock-time').textContent = h + ':' + m;
  const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  document.getElementById('lock-date').textContent =
    days[now.getDay()] + ', ' + months[now.getMonth()] + ' ' + now.getDate();
}

function checkPassword() {
  const input = document.getElementById('lock-input').value.trim().toLowerCase();
  const card  = document.querySelector('.lock-card');
  const error = document.getElementById('lock-error');
  if (input === 'ajewole') {
    error.textContent = '';
    const flash = document.createElement('div');
    flash.className = 'unlock-flash';
    document.body.appendChild(flash);
    spawnHearts('floating-hearts-lock', 30, 100);
    setTimeout(() => {
      flash.remove();
      goToPage('page-lock', 'page-gallery');
      setTimeout(initGallery, 600);
    }, 900);
  } else {
    card.classList.remove('shake');
    void card.offsetWidth;
    card.classList.add('shake');
    error.textContent = 'Oops… wrong password sweetheart ❤️';
    document.getElementById('lock-input').value = '';
    setTimeout(() => { error.textContent = ''; }, 3000);
  }
}

// ===== PAGE 3: GALLERY =====
function initGallery() {
  IMGS.forEach((src, i) => {
    const slide = document.getElementById('slide-' + i);
    if (slide) slide.style.backgroundImage = `url('${src}')`;
  });
  const dotsContainer = document.getElementById('progress-dots');
  IMGS.forEach((_, i) => {
    const dot = document.createElement('div');
    dot.className = 'dot' + (i===0?' active':'');
    dot.id = 'dot-' + i;
    dotsContainer.appendChild(dot);
  });
  spawnParticles('gallery-particles', 35);
  spawnHearts('floating-hearts-gallery', 0, 900);
  showCaption(0);
  startGalleryTimer();
  document.getElementById('page-gallery').addEventListener('click', advanceSlide);
}

function showCaption(index) {
  const el = document.getElementById('caption-text');
  el.style.animation = 'none'; void el.offsetWidth;
  el.textContent = CAPTIONS[index] || '';
  el.style.animation = 'captionIn 1s ease forwards';
}

function startGalleryTimer() {
  if (galleryTimer) clearInterval(galleryTimer);
  galleryTimer = setInterval(advanceSlide, 6000);
}

function advanceSlide() {
  const slides = document.querySelectorAll('.slide');
  const dots   = document.querySelectorAll('.dot');
  slides[currentSlide].classList.remove('active');
  if (dots[currentSlide]) dots[currentSlide].classList.remove('active');
  currentSlide++;
  if (currentSlide >= IMGS.length) {
    clearInterval(galleryTimer);
    goToPage('page-gallery', 'page-final');
    setTimeout(initFinal, 500);
    return;
  }
  slides[currentSlide].classList.add('active');
  if (dots[currentSlide]) dots[currentSlide].classList.add('active');
  showCaption(currentSlide);
  startGalleryTimer();
}

// ===== PAGE 4: FINAL =====
function initFinal() {
  spawnParticles('final-particles', 40);
  spawnHearts('floating-hearts-final', 0, 700);
}

function revealCreator() {
  document.getElementById('question-card').style.display = 'none';
  const reveal = document.getElementById('reveal-card');
  reveal.classList.add('show');
  burstSparkles('reveal-sparkles', 60);
  spawnHearts('floating-hearts-final', 50, 150);
  setTimeout(() => burstSparkles('reveal-sparkles', 40), 800);
}

function noBtn() {
  const btn = document.querySelector('.btn-no');
  btn.textContent = 'Are you sure? 🥺';
  setTimeout(() => {
    btn.textContent = 'Come on… YES! 💖';
    btn.onclick = revealCreator;
    btn.style.background = 'linear-gradient(135deg,#ff3d7f,#9b59b6)';
    btn.style.color = '#fff';
  }, 1500);
}

function burstSparkles(containerId, count) {
  const container = document.getElementById(containerId);
  if (!container) return;
  for (let i=0; i<count; i++) {
    const s = document.createElement('div');
    s.className = 'sparkle';
    const angle = Math.random()*360;
    const dist  = 30 + Math.random()*100;
    const tx = Math.cos(angle*Math.PI/180)*dist + 'px';
    const ty = Math.sin(angle*Math.PI/180)*dist + 'px';
    s.style.cssText = `
      left:${20+Math.random()*60}%;
      top:${20+Math.random()*60}%;
      --tx:${tx}; --ty:${ty};
      background:${['#ffd700','#ff6b9d','#fff','#c084fc'][Math.floor(Math.random()*4)]};
      width:${4+Math.random()*8}px; height:${4+Math.random()*8}px;
      animation-duration:${0.5+Math.random()*0.8}s;
      animation-delay:${Math.random()*0.4}s;
    `;
    container.appendChild(s);
    setTimeout(() => s.remove(), 2000);
  }
}

// ===== INIT =====
window.addEventListener('DOMContentLoaded', () => {
  initWelcome();
  document.addEventListener('touchmove', e => e.preventDefault(), {passive:false});
});
